  trigger.focus(); // Return focus to trigger
});

document.addEventListener('keydown', (e) => {
  if (e.key === 'Escape' && !dialog.hidden) {
    dialog.hidden = true;
    trigger.focus();
  }
});

function trapFocus(container: HTMLElement) {
  const focusable = container.querySelectorAll(
    'button, [href], input, select, textarea, [tabindex]:not([tabindex="-1"])'
  );
  const first = focusable[0];
  const last = focusable[focusable.length - 1];

  container.addEventListener('keydown', (e) => {
    if (e.key !== 'Tab') return;
    if (e.shiftKey) {
      if (document.activeElement === first) {
        e.preventDefault();
        last?.focus();
      }
    } else {
      if (document.activeElement === last) {
        e.preventDefault();
        first?.focus();
      }
    }
  });
}
```

Also ensure the modal does **not visually obscure** the focused element *outside* it when open — use `position: fixed`, `inset: 0`, and `overflow: auto` on the dialog, and do not block scroll. If obscuring is unavoidable, ensure `Escape` dismisses the dialog and restores focus + visibility.

